
  create table "public"."knockoutlock" (
    "id" bigint generated by default as identity not null,
    "locked" boolean
      );


alter table "public"."knockoutlock" enable row level security;

alter table "public"."knockout_round_points" disable row level security;

CREATE UNIQUE INDEX knockoutlock_pkey ON public.knockoutlock USING btree (id);

alter table "public"."knockoutlock" add constraint "knockoutlock_pkey" PRIMARY KEY using index "knockoutlock_pkey";

grant delete on table "public"."knockoutlock" to "anon";

grant insert on table "public"."knockoutlock" to "anon";

grant references on table "public"."knockoutlock" to "anon";

grant select on table "public"."knockoutlock" to "anon";

grant trigger on table "public"."knockoutlock" to "anon";

grant truncate on table "public"."knockoutlock" to "anon";

grant update on table "public"."knockoutlock" to "anon";

