grant trigger on table "public"."knockoutlock" to "authenticated";

grant truncate on table "public"."knockoutlock" to "authenticated";

grant update on table "public"."knockoutlock" to "authenticated";

grant delete on table "public"."knockoutlock" to "service_role";

