  create policy "Allow authenticated users to read all profiles"
  on "public"."profiles"
  as permissive
  for select
  to authenticated
using (true);



  create policy "Allow users to insert their own profile"
  on "public"."profiles"
  as permissive
  for insert
  to authenticated
with check ((auth.uid() = id));



  create policy "Allow users to update their own profile"
  on "public"."profiles"
  as permissive
  for update
  to authenticated
using ((auth.uid() = id))
with check ((auth.uid() = id));



  create policy "Allow authenticated users to read all scores"
  on "public"."user_scores"
  as permissive
  for select
  to authenticated
using (true);



  create policy "Allow service role to insert scores"
  on "public"."user_scores"
  as permissive
  for insert
  to service_role
with check (true);



  create policy "Allow service role to update scores"
  on "public"."user_scores"
  as permissive
  for update
  to service_role
using (true)
with check (true);



  create policy "Allow users to update their own scores"
  on "public"."user_scores"
  as permissive
  for update
  to authenticated
using ((auth.uid() = user_id))
with check ((auth.uid() = user_id));



